create table if not exists profiles(id uuid primary key,email text,plan text default 'free',stripe_customer_id text,business jsonb default '{}',created_at timestamptz default now());
create table if not exists customers(id uuid primary key default gen_random_uuid(),user_id uuid,name text not null,phone text,email text,address text,logo text,notes text,archived boolean default false,created_at timestamptz default now());
create table if not exists invoices(id uuid primary key default gen_random_uuid(),user_id uuid,invoice_number text,status text default 'Draft',currency text default 'AUD',language text default 'English',template_id text default 'nova',customer jsonb default '{}',business jsonb default '{}',items jsonb default '[]',issue_date text,due_date text,notes text,payment_qr text,created_at timestamptz default now());
create table if not exists usage_limits(id uuid primary key default gen_random_uuid(),user_id uuid,month_key text,invoices_created integer default 0,ai_generations integer default 0,reminders_sent integer default 0,created_at timestamptz default now(),unique(user_id,month_key));
